INSERT INTO perfil (
  id, condominio_id, nome_completo, email, whatsapp,
  bloco_txt, apto_txt, papel_sistema, tipo_morador,
  status_aprovacao, whatsapp_msg_consent, botconversa_id, needs_password_setup
)
SELECT
  au.id, m.condo_id::uuid, m.nome, m.email, m.cel,
  m.bloco, m.apto, m.papel, m.tipo,
  m.status, m.zap::boolean, m.botconv, true
FROM moradores m
JOIN auth.users au ON au.email = m.email
ON CONFLICT (id) DO NOTHING;
